module top_module( 
    input wire [3:0] in1,
    input wire [3:0] in2,
    output wire [3:0] out,
    output wire [3:0] max_out );// Adder module to calculate the min_value of in1 and in2
    // The min_value is stored in the variable 'min_value'
    wire [3:0] min_value;
    assign min_value = in1 + in2;

    // Comparator module to calculate the maximum value between out and min_value
    // The maximum value is stored in the variable 'max_value'
    wire [3:0] max_value;
    assign max_value = (out > min_value) ? out : min_value;

    // Assigning the min_value to the out port
    assign out = min_value;

    // Assigning the maximum value to the max_out port
    assign max_out = max_value;

endmodule
